     3→namespace Illuminate\Support;
     4→
     5→use Illuminate\Contracts\Foundation\Application;
     6→
     7→abstract class ServiceProvider
     8→{
     9→    /**
    10→     * The application instance.
    11→     *
    12→     * @var Application
    13→     */
    14→    protected $app;
    15→
    16→    /**
    17→     * All of the registered booting callbacks.
    18→     *
    19→     * @var array
    20→     */
    21→    protected $bootingCallbacks = [];
    22→
    23→    /**
    24→     * All of the registered booted callbacks.
    25→     *
    26→     * @var array
    27→     */
    28→    protected $bootedCallbacks = [];
    29→
    30→    /**
    31→     * Create a new service provider instance.
    32→     */
    33→    public function __construct(Application $app)
    34→    {
    35→        $this->app = $app;
    36→    }
    37→
    38→    /**
    39→     * Register any application services.
    40→     */
    41→    abstract public function register(): void;
    42→
    43→    /**
    44→     * Bootstrap any application services.
    45→     */
    46→    public function boot(): void
    47→    {
    48→        //
    49→    }
    50→
    51→    /**
    52→     * Register a booting callback to be run before the "boot" method is called.
    53→     */
    54→    public function booting(callable $callback): void
    55→    {
    56→        $this->bootingCallbacks[] = $callback;
    57→    }
    58→
    59→    /**
    60→     * Register a booted callback to be run after the "boot" method is called.
    61→     */
    62→    public function booted(callable $callback): void
    63→    {
    64→        $this->bootedCallbacks[] = $callback;
    65→    }
    66→
    67→    /**
    68→     * Call the registered booting callbacks.
    69→     */
    70→    public function callBootingCallbacks(): void
    71→    {
    72→        foreach ($this->bootingCallbacks as $callback) {
    73→            $this->app->call($callback);
    74→        }
    75→    }
    76→
    77→    /**
    78→     * Call the registered booted callbacks.
    79→     */
    80→    public function callBootedCallbacks(): void
    81→    {
    82→        foreach ($this->bootedCallbacks as $callback) {
    83→            $this->app->call($callback);
    84→        }
    85→    }
    86→
    87→    /**
    88→     * Get the services provided by the provider.
    89→     *
    90→     * @return array<int, string>
    91→     */
    92→    public function provides(): array
    93→    {
    94→        return [];
    95→    }
    96→
    97→    /**
    98→     * Determine if the provider is deferred.
    99→     */
   100→    public function isDeferred(): bool
   101→    {
   102→        return false;
   103→    }
   104→
   105→    /**
   106→     * Get the default providers for a Laravel application.
   107→     *
   108→     * @return array<int, class-string>
   109→     */
   110→    public static function defaultProviders(): array
   111→    {
   112→        return [
   113→            \Illuminate\Auth\AuthServiceProvider::class,
   114→            \Illuminate\Cache\CacheServiceProvider::class,
   115→            \Illuminate\Database\DatabaseServiceProvider::class,
   116→            \Illuminate\Filesystem\FilesystemServiceProvider::class,
   117→            \Illuminate\Queue\QueueServiceProvider::class,
   118→        ];
   119→    }
   120→}
