     1→<?php
     2→
     3→namespace Illuminate\Container;
     4→
     5→use Illuminate\Contracts\Container\Container;
     6→use Illuminate\Contracts\Container\ContextualBindingBuilder as ContextualBindingBuilderContract;
     7→
     8→class ContextualBindingBuilder implements ContextualBindingBuilderContract
     9→{
    10→    /**
    11→     * The underlying container instance.
    12→     *
    13→     * @var Container
    14→     */
    15→    protected $container;
    16→
    17→    /**
    18→     * The concrete instance(s) that the contextual binding applies to.
    19→     *
    20→     * @var string|array
    21→     */
    22→    protected $concrete;
    23→
    24→    /**
    25→     * The abstract target that the contextual binding should resolve.
    26→     *
    27→     * @var string
    28→     */
    29→    protected $needs;
    30→
    31→    /**
    32→     * Create a new contextual binding builder.
    33→     */
    34→    public function __construct(Container $container, $concrete)
    35→    {
    36→        $this->container = $container;
    37→        $this->concrete = $concrete;
    38→    }
    39→
    40→    /**
    41→     * Define the abstract target that the contextual binding should resolve.
    42→     *
    43→     * @param  string  $abstract
    44→     * @return $this
    45→     */
    46→    public function needs(string $abstract): self
    47→    {
    48→        $this->needs = $abstract;
    49→
    50→        return $this;
    51→    }
    52→
    53→    /**
    54→     * Define the implementation for the contextual binding.
    55→     *
    56→     * @param  \Closure|string|array  $implementation
    57→     * @return void
    58→     */
    59→    public function give($implementation): void
    60→    {
    61→        foreach ($this->normalizeConcrete() as $concrete) {
    62→            $this->container->addContextualBinding(
    63→                $concrete,
    64→                $this->needs,
    65→                $implementation
    66→            );
    67→        }
    68→    }
    69→
    70→    /**
    71→     * Define tagged services to be used as the implementation for the contextual binding.
    72→     *
    73→     * @param  string  $tag
    74→     * @return void
    75→     */
    76→    public function giveTagged(string $tag): void
    77→    {
    78→        $this->give(function ($container) use ($tag) {
    79→            $taggedServices = $container->tagged($tag);
    80→
    81→            return is_array($taggedServices) ? $taggedServices : iterator_to_array($taggedServices);
    82→        });
    83→    }
    84→
    85→    /**
    86→     * Specify the configuration item to bind as a primitive.
    87→     *
    88→     * @param  string  $key
    89→     * @param  mixed  $default
    90→     * @return void
    91→     */
    92→    public function giveConfig(string $key, $default = null): void
    93→    {
    94→        $this->give(function ($container) use ($key, $default) {
    95→            return $container->make('config')->get($key, $default);
    96→        });
    97→    }
    98→
    99→    /**
   100→     * Normalize the concrete bindings into an array.
   101→     *
   102→     * @return array
   103→     */
   104→    protected function normalizeConcrete(): array
   105→    {
   106→        return is_array($this->concrete) ? $this->concrete : [$this->concrete];
   107→    }
   108→}
   109→

