     1→<?php
     2→
     3→namespace Illuminate\Container;
     4→
     5→use ArrayAccess;
     6→use Closure;
     7→use Exception;
     8→use Illuminate\Contracts\Container\BindingResolutionException;
     9→use Illuminate\Contracts\Container\CircularDependencyException;
    10→use Illuminate\Contracts\Container\Container as ContainerContract;
    11→use Illuminate\Contracts\Container\ContextualAttribute;
    12→use LogicException;
    13→use ReflectionAttribute;
    14→use ReflectionClass;
    15→use ReflectionException;
    16→use ReflectionFunction;
    17→use ReflectionParameter;
    18→use TypeError;
    19→
    20→class Container implements ArrayAccess, ContainerContract
    21→{
    22→    /**
    23→     * The current globally available container (if any).
    24→     *
    25→     * @var static
    26→     */
    27→    protected static $instance;
    28→
    29→    /**
    30→     * An array of the types that have been resolved.
    31→     *
    32→     * @var bool[]
    33→     */
    34→    protected $resolved = [];
    35→
    36→    /**
    37→     * The container's bindings.
    38→     *
    39→     * @var array[]
    40→     */
    41→    protected $bindings = [];
    42→
    43→    /**
    44→     * The container's method bindings.
    45→     *
    46→     * @var \Closure[]
    47→     */
    48→    protected $methodBindings = [];
    49→
    50→    /**
    51→     * The container's shared instances.
    52→     *
    53→     * @var object[]
    54→     */
    55→    protected $instances = [];
    56→
    57→    /**
    58→     * The container's scoped instances.
    59→     *
    60→     * @var array
    61→     */
    62→    protected $scopedInstances = [];
    63→
    64→    /**
    65→     * The registered type aliases.
    66→     *
    67→     * @var string[]
    68→     */
    69→    protected $aliases = [];
    70→
    71→    /**
    72→     * The registered aliases keyed by the abstract name.
    73→     *
    74→     * @var array[]
    75→     */
    76→    protected $abstractAliases = [];
    77→
    78→    /**
    79→     * The extension closures for services.
    80→     *
    81→     * @var array[]
    82→     */
    83→    protected $extenders = [];
    84→
    85→    /**
    86→     * All of the registered tags.
    87→     *
    88→     * @var array[]
    89→     */
    90→    protected $tags = [];
    91→
    92→    /**
    93→     * The stack of concretions currently being built.
    94→     *
    95→     * @var array[]
    96→     */
    97→    protected $buildStack = [];
    98→
    99→    /**
   100→     * The parameter override stack.
   101→     *
   102→     * @var array[]
   103→     */
   104→    protected $with = [];
   105→
   106→    /**
   107→     * The contextual binding map.
   108→     *
   109→     * @var array[]
   110→     */
   111→    public $contextual = [];
   112→
   113→    /**
   114→     * The contextual attribute handlers.
   115→     *
   116→     * @var array[]
   117→     */
   118→    public $contextualAttributes = [];
   119→
   120→    /**
   121→     * All of the registered rebound callbacks.
   122→     *
   123→     * @var array[]
   124→     */
   125→    protected $reboundCallbacks = [];
   126→
   127→    /**
   128→     * All of the global before resolving callbacks.
   129→     *
   130→     * @var \Closure[]
   131→     */
   132→    protected $globalBeforeResolvingCallbacks = [];
   133→
   134→    /**
   135→     * All of the global resolving callbacks.
   136→     *
   137→     * @var \Closure[]
   138→     */
   139→    protected $globalResolvingCallbacks = [];
   140→
   141→    /**
   142→     * All of the global after resolving callbacks.
   143→     *
   144→     * @var \Closure[]
   145→     */
   146→    protected $globalAfterResolvingCallbacks = [];
   147→
   148→    /**
   149→     * All of the before resolving callbacks by class type.
   150→     *
   151→     * @var array[]
   152→     */
   153→    protected $beforeResolvingCallbacks = [];
   154→
   155→    /**
   156→     * All of the resolving callbacks by class type.
   157→     *
   158→     * @var array[]
   159→     */
   160→    protected $resolvingCallbacks = [];
   161→
   162→    /**
   163→     * All of the after resolving callbacks by class type.
   164→     *
   165→     * @var array[]
   166→     */
   167→    protected $afterResolvingCallbacks = [];
   168→
   169→    /**
   170→     * All of the after resolving attribute callbacks by class type.
   171→     *
   172→     * @var array[]
   173→     */
   174→    protected $afterResolvingAttributeCallbacks = [];
   175→
   176→    /**
   177→     * Define a contextual binding.
   178→     *
   179→     * @param  array|string  $concrete
   180→     * @return \Illuminate\Contracts\Container\ContextualBindingBuilder
   181→     */
   182→    public function when($concrete)
   183→    {
   184→        $aliases = [];
   185→
   186→        foreach (Util::arrayWrap($concrete) as $c) {
   187→            $aliases[] = $this->getAlias($c);
   188→        }
   189→
   190→        return new ContextualBindingBuilder($this, $aliases);
   191→    }
   192→
   193→    /**
   194→     * Define a contextual binding based on an attribute.
   195→     *
   196→     * @param  string  $attribute
   197→     * @param  \Closure  $handler
   198→     * @return void
   199→     */
   200→    public function whenHasAttribute(string $attribute, Closure $handler)
   201→    {
   202→        $this->contextualAttributes[$attribute] = $handler;
   203→    }
   204→
   205→    /**
   206→     * Determine if the given abstract type has been bound.
   207→     *
   208→     * @param  string  $abstract
   209→     * @return bool
   210→     */
   211→    public function bound($abstract)
   212→    {
   213→        return isset($this->bindings[$abstract]) ||
   214→               isset($this->instances[$abstract]) ||
   215→               $this->isAlias($abstract);
   216→    }
   217→
   218→    /**
   219→     * {@inheritdoc}
   220→     *
   221→     * @return bool
   222→     */
   223→    public function has(string $id): bool
   224→    {
   225→        return $this->bound($id);
   226→    }
   227→
   228→    /**
   229→     * Determine if the given abstract type has been resolved.
   230→     *
   231→     * @param  string  $abstract
   232→     * @return bool
   233→     */
   234→    public function resolved($abstract)
   235→    {
   236→        if ($this->isAlias($abstract)) {
   237→            $abstract = $this->getAlias($abstract);
   238→        }
   239→
   240→        return isset($this->resolved[$abstract]) ||
   241→               isset($this->instances[$abstract]);
   242→    }
   243→
   244→    /**
   245→     * Determine if a given type is shared.
   246→     *
   247→     * @param  string  $abstract
   248→     * @return bool
   249→     */
   250→    public function isShared($abstract)
   251→    {
   252→        return isset($this->instances[$abstract]) ||
   253→               (isset($this->bindings[$abstract]['shared']) &&
   254→               $this->bindings[$abstract]['shared'] === true);
   255→    }
   256→
   257→    /**
   258→     * Determine if a given string is an alias.
   259→     *
   260→     * @param  string  $name
   261→     * @return bool
   262→     */
   263→    public function isAlias($name)
   264→    {
   265→        return isset($this->aliases[$name]);
   266→    }
   267→
   268→    /**
   269→     * Register a binding with the container.
   270→     *
   271→     * @param  string  $abstract
   272→     * @param  \Closure|string|null  $concrete
   273→     * @param  bool  $shared
   274→     * @return void
   275→     *
   276→     * @throws \TypeError
   277→     */
   278→    public function bind($abstract, $concrete = null, $shared = false)
   279→    {
   280→        $this->dropStaleInstances($abstract);
   281→
   282→        // If no concrete type was given, we will simply set the concrete type to the
   283→        // abstract type. After that, the concrete type to be registered as shared
   284→        // without being forced to state their classes in both of the parameters.
   285→        if (is_null($concrete)) {
   286→            $concrete = $abstract;
   287→        }
   288→
   289→        // If the factory is not a Closure, it means it is just a class name which is
   290→        // bound into this container to the abstract type and we will just wrap it
   291→        // up inside its own Closure to give us more convenience when extending.
   292→        if (! $concrete instanceof Closure) {
   293→            if (! is_string($concrete)) {
   294→                throw new TypeError(self::class.'::bind(): Argument #2 ($concrete) must be of type Closure|string|null');
   295→            }
   296→
   297→            $concrete = $this->getClosure($abstract, $concrete);
   298→        }
   299→
   300→        $this->bindings[$abstract] = ['concrete' => $concrete, 'shared' => $shared];
   301→
   302→        // If the abstract type was already resolved in this container we'll fire the
   303→        // rebound listener so that any objects which have already gotten resolved
   304→        // can have their copy of the object updated via the listener callbacks.
   305→        if ($this->resolved($abstract)) {
   306→            $this->rebound($abstract);
   307→        }
   308→    }
   309→
   310→    /**
   311→     * Get the Closure to be used when building a type.
   312→     *
   313→     * @param  string  $abstract
   314→     * @param  string  $concrete
   315→     * @return \Closure
   316→     */
   317→    protected function getClosure($abstract, $concrete)
   318→    {
   319→        return function ($container, $parameters = []) use ($abstract, $concrete) {
   320→            if ($abstract == $concrete) {
   321→                return $container->build($concrete);
   322→            }
   323→
   324→            return $container->resolve(
   325→                $concrete, $parameters, $raiseEvents = false
   326→            );
   327→        };
   328→    }
   329→
   330→    /**
   331→     * Determine if the container has a method binding.
   332→     *
   333→     * @param  string  $method
   334→     * @return bool
   335→     */
   336→    public function hasMethodBinding($method)
   337→    {
   338→        return isset($this->methodBindings[$method]);
   339→    }
   340→
   341→    /**
   342→     * Bind a callback to resolve with Container::call.
   343→     *
   344→     * @param  array|string  $method
   345→     * @param  \Closure  $callback
   346→     * @return void
   347→     */
   348→    public function bindMethod($method, $callback)
   349→    {
   350→        $this->methodBindings[$this->parseBindMethod($method)] = $callback;
   351→    }
   352→
   353→    /**
   354→     * Get the method to be bound in class@method format.
   355→     *
   356→     * @param  array|string  $method
   357→     * @return string
   358→     */
   359→    protected function parseBindMethod($method)
   360→    {
   361→        if (is_array($method)) {
   362→            return $method[0].'@'.$method[1];
   363→        }
   364→
   365→        return $method;
   366→    }
   367→
   368→    /**
   369→     * Get the method binding for the given method.
   370→     *
   371→     * @param  string  $method
   372→     * @param  mixed  $instance
   373→     * @return mixed
   374→     */
   375→    public function callMethodBinding($method, $instance)
   376→    {
   377→        return call_user_func($this->methodBindings[$method], $instance, $this);
   378→    }
   379→
   380→    /**
   381→     * Add a contextual binding to the container.
   382→     *
   383→     * @param  string  $concrete
   384→     * @param  string  $abstract
   385→     * @param  \Closure|string  $implementation
   386→     * @return void
   387→     */
   388→    public function addContextualBinding($concrete, $abstract, $implementation)
   389→    {
   390→        $this->contextual[$concrete][$this->getAlias($abstract)] = $implementation;
   391→    }
   392→
   393→    /**
   394→     * Register a binding if it hasn't already been registered.
   395→     *
   396→     * @param  string  $abstract
   397→     * @param  \Closure|string|null  $concrete
   398→     * @param  bool  $shared
   399→     * @return void
   400→     */
   401→    public function bindIf($abstract, $concrete = null, $shared = false)
   402→    {
   403→        if (! $this->bound($abstract)) {
   404→            $this->bind($abstract, $concrete, $shared);
   405→        }
   406→    }
   407→
   408→    /**
   409→     * Register a shared binding in the container.
   410→     *
   411→     * @param  string  $abstract
   412→     * @param  \Closure|string|null  $concrete
   413→     * @return void
   414→     */
   415→    public function singleton($abstract, $concrete = null)
   416→    {
   417→        $this->bind($abstract, $concrete, true);
   418→    }
   419→
   420→    /**
   421→     * Register a shared binding if it hasn't already been registered.
   422→     *
   423→     * @param  string  $abstract
   424→     * @param  \Closure|string|null  $concrete
   425→     * @return void
   426→     */
   427→    public function singletonIf($abstract, $concrete = null)
   428→    {
   429→        if (! $this->bound($abstract)) {
   430→            $this->singleton($abstract, $concrete);
   431→        }
   432→    }
   433→
   434→    /**
   435→     * Register a scoped binding in the container.
   436→     *
   437→     * @param  string  $abstract
   438→     * @param  \Closure|string|null  $concrete
   439→     * @return void
   440→     */
   441→    public function scoped($abstract, $concrete = null)
   442→    {
   443→        $this->scopedInstances[] = $abstract;
   444→
   445→        $this->singleton($abstract, $concrete);
   446→    }
   447→
   448→    /**
   449→     * Register a scoped binding if it hasn't already been registered.
   450→     *
   451→     * @param  string  $abstract
   452→     * @param  \Closure|string|null  $concrete
   453→     * @return void
   454→     */
   455→    public function scopedIf($abstract, $concrete = null)
   456→    {
   457→        if (! $this->bound($abstract)) {
   458→            $this->scoped($abstract, $concrete);
   459→        }
   460→    }
   461→
   462→    /**
   463→     * "Extend" an abstract type in the container.
   464→     *
   465→     * @param  string  $abstract
   466→     * @param  \Closure  $closure
   467→     * @return void
   468→     *
   469→     * @throws \InvalidArgumentException
   470→     */
   471→    public function extend($abstract, Closure $closure)
   472→    {
   473→        $abstract = $this->getAlias($abstract);
   474→
   475→        if (isset($this->instances[$abstract])) {
   476→            $this->instances[$abstract] = $closure($this->instances[$abstract], $this);
   477→
   478→            $this->rebound($abstract);
   479→        } else {
   480→            $this->extenders[$abstract][] = $closure;
   481→
   482→            if ($this->resolved($abstract)) {
   483→                $this->rebound($abstract);
   484→            }
   485→        }
   486→    }
   487→
   488→    /**
   489→     * Register an existing instance as shared in the container.
   490→     *
   491→     * @template TInstance of mixed
   492→     *
   493→     * @param  string  $abstract
   494→     * @param  TInstance  $instance
   495→     * @return TInstance
   496→     */
   497→    public function instance($abstract, $instance)
   498→    {
   499→        $this->removeAbstractAlias($abstract);
   500→
   501→        $isBound = $this->bound($abstract);
   502→
   503→        unset($this->aliases[$abstract]);
   504→
   505→        // We'll check to determine if this type has been bound before, and if it has
   506→        // we will fire the rebound callbacks registered with the container and it
   507→        // can be updated with consuming classes that have gotten resolved here.
   508→        $this->instances[$abstract] = $instance;
   509→
   510→        if ($isBound) {
   511→            $this->rebound($abstract);
   512→        }
   513→
   514→        return $instance;
   515→    }
   516→
   517→    /**
   518→     * Remove an alias from the contextual binding alias cache.
   519→     *
   520→     * @param  string  $searched
